import buildDebug from 'debug'
import { Request, Response, NextFunction } from 'express'
import leoProfanity from 'leo-profanity'

import de from 'naughty-words/de.json'
import fr from 'naughty-words/fr.json'

const debug = buildDebug('verdaccio:plugin:pro:middleware:profanity')

// English: leo-profanity default (Shutterstock / LDNOOBW-style list). DE/FR: naughty-words (LDNOOBW).
leoProfanity.reset()
leoProfanity.add(de)
leoProfanity.add(fr)

function valueContainsProfanity(value: unknown): boolean {
  if (value === null || value === undefined) {
    return false
  }
  if (typeof value === 'string') {
    return leoProfanity.check(value)
  }
  if (typeof value === 'number' || typeof value === 'boolean') {
    return leoProfanity.check(String(value))
  }
  if (Array.isArray(value)) {
    for (let i = 0; i < value.length; i++) {
      if (valueContainsProfanity(value[i])) {
        return true
      }
    }
    return false
  }
  if (typeof value === 'object') {
    const o = value as Record<string, unknown>
    const keys = Object.keys(o)
    for (let i = 0; i < keys.length; i++) {
      if (valueContainsProfanity(o[keys[i]])) {
        return true
      }
    }
    return false
  }
  return false
}

// Scans parsed JSON bodies only (run after express.json).
const profanityFilter = (req: Request, res: Response, next: NextFunction): void => {
  if (req.method === 'GET' || req.method === 'HEAD') {
    next()
    return
  }
  if (req.body === undefined || req.body === null) {
    next()
    return
  }
  if (valueContainsProfanity(req.body)) {
    debug('request body contained profanity')
    res.status(400).send('Bad Request')
    return
  }
  next()
}

export default profanityFilter
