import buildDebug from 'debug'
import { Request, Response, NextFunction } from 'express'
import { parse } from 'tldts'

import { BLOCKED_REGISTRABLE_DOMAINS } from './blocked-adult-domains'

const debug = buildDebug('verdaccio:plugin:pro:middleware:blacklist')

const blocked = new Set<string>(BLOCKED_REGISTRABLE_DOMAINS)

// href="..." / src="..." (common in HTML fragments stored in JSON)
const hrefSrcRe = /(?:\bhref\s*=|\bsrc\s*=)\s*["']([^"']+)["']/gi
// Absolute http(s) URLs
const absoluteUrlRe = /https?:\/\/[^\s"'<>\]]+/gi
// Protocol-relative URLs (not already matched as part of https://)
const protocolRelativeRe = /(?<![:\w])\/\/[^\s"'<>\]]+/gi

function registrableDomainFromUrlLike(raw: string): string | null {
  const trimmed = raw.trim()
  if (!trimmed) {
    return null
  }
  const withScheme = trimmed.startsWith('//') ? `https:${trimmed}` : trimmed
  if (!/^https?:\/\//i.test(withScheme)) {
    return null
  }
  const { domain, isIp, isPrivate } = parse(withScheme)
  if (!domain || isIp || isPrivate) {
    return null
  }
  return domain
}

function stringContainsBlockedUrl(text: string): boolean {
  let m: RegExpExecArray | null

  hrefSrcRe.lastIndex = 0
  while ((m = hrefSrcRe.exec(text)) !== null) {
    const reg = registrableDomainFromUrlLike(m[1])
    if (reg && blocked.has(reg)) {
      return true
    }
  }

  absoluteUrlRe.lastIndex = 0
  while ((m = absoluteUrlRe.exec(text)) !== null) {
    const reg = registrableDomainFromUrlLike(m[0])
    if (reg && blocked.has(reg)) {
      return true
    }
  }

  protocolRelativeRe.lastIndex = 0
  while ((m = protocolRelativeRe.exec(text)) !== null) {
    const reg = registrableDomainFromUrlLike(m[0])
    if (reg && blocked.has(reg)) {
      return true
    }
  }

  return false
}

function valueContainsBlockedUrl(value: unknown): boolean {
  if (value === null || value === undefined) {
    return false
  }
  if (typeof value === 'string') {
    return stringContainsBlockedUrl(value)
  }
  if (typeof value === 'number' || typeof value === 'boolean') {
    return stringContainsBlockedUrl(String(value))
  }
  if (Array.isArray(value)) {
    for (let i = 0; i < value.length; i++) {
      if (valueContainsBlockedUrl(value[i])) {
        return true
      }
    }
    return false
  }
  if (typeof value === 'object') {
    const o = value as Record<string, unknown>
    const keys = Object.keys(o)
    for (let i = 0; i < keys.length; i++) {
      if (valueContainsBlockedUrl(o[keys[i]])) {
        return true
      }
    }
    return false
  }
  return false
}

// Scans parsed JSON bodies only (run after express.json).
const blacklistFilter = (req: Request, res: Response, next: NextFunction): void => {
  if (req.method === 'GET' || req.method === 'HEAD') {
    next()
    return
  }
  if (req.body === undefined || req.body === null) {
    next()
    return
  }
  if (valueContainsBlockedUrl(req.body)) {
    debug('request body contained a blocked URL')
    res.status(400).send('Bad Request')
    return
  }
  next()
}

export default blacklistFilter
